// ============================================================
// Plugin Manager - Handles loading and executing plugins
// ============================================================
class PluginManager {
  constructor() {
    this.plugins = new Map();
    this.hooks = {
      onRequest: [],
      onResponse: [],
      onError: [],
      onStartup: [],
      onShutdown: [],
    };
  }

  // Load plugins from a configuration file
  loadFromConfig(configPath) {
    const resolvedPath = path.resolve(configPath);
    if (!fs.existsSync(resolvedPath)) {
      console.warn(`[PluginManager] Config file not found: ${resolvedPath}`);
      return;
    }

    const config = JSON.parse(fs.readFileSync(resolvedPath, 'utf-8'));

    if (config.plugins && Array.isArray(config.plugins)) {
      for (const pluginDef of config.plugins) {
        this.loadPlugin(pluginDef);
      }
    }
  }

  // Load plugins from environment variables
  loadFromEnv() {
    // GATEWAY_PLUGINS: comma-separated list of plugin module paths
    const pluginPaths = process.env.GATEWAY_PLUGINS;
    if (pluginPaths) {
      const paths = pluginPaths.split(',').map(p => p.trim());
      for (const p of paths) {
        this.loadPlugin({ name: path.basename(p, '.js'), type: 'file', path: p });
      }
    }

    // GATEWAY_PLUGIN_INLINE_<NAME>: inline plugin code from env vars
    for (const [key, value] of Object.entries(process.env)) {
      if (key.startsWith('GATEWAY_PLUGIN_INLINE_')) {
        const name = key.replace('GATEWAY_PLUGIN_INLINE_', '').toLowerCase();
        this.loadPlugin({ name, type: 'inline', code: value });
      }
    }
  }

  // Load a single plugin definition
  loadPlugin(pluginDef) {
    const { name, type, enabled = true } = pluginDef;

    if (!enabled) {
      console.log(`[PluginManager] Plugin "${name}" is disabled, skipping.`);
      return;
    }

    console.log(`[PluginManager] Loading plugin "${name}" (type: ${type})...`);

    try {
      let pluginModule;

      switch (type) {
        case 'file':
          pluginModule = this._loadFromFile(pluginDef);
          break;
        case 'npm':
          pluginModule = this._loadFromNpm(pluginDef);
          break;
        case 'inline':
          pluginModule = this._loadInline(pluginDef);
          break;
        case 'sandbox':
          pluginModule = this._loadSandboxed(pluginDef);
          break;
        default:
          throw new Error(`Unknown plugin type: ${type}`);
      }

      if (pluginModule) {
        // Initialize plugin if it has an init function
        if (typeof pluginModule.init === 'function') {
          pluginModule.init(pluginDef.config || {});
        }

        // Register hooks
        this._registerHooks(name, pluginModule, pluginDef.priority || 10);
        this.plugins.set(name, { definition: pluginDef, module: pluginModule });
        console.log(`[PluginManager] Plugin "${name}" loaded successfully.`);
      }
    } catch (error) {
      console.error(`[PluginManager] Failed to load plugin "${name}":`, error.message);
    }
  }

  // Load plugin from a file path using require()
  _loadFromFile(pluginDef) {
    const pluginPath = path.resolve(pluginDef.path);

    // Security: Validate the path is within allowed directories
    const allowedDirs = (process.env.GATEWAY_PLUGIN_DIRS || './plugins').split(',').map(d => path.resolve(d.trim()));
    const isAllowed = allowedDirs.some(dir => pluginPath.startsWith(dir));

    if (!isAllowed) {
      throw new Error(`Plugin path "${pluginPath}" is not within allowed directories: ${allowedDirs.join(', ')}`);
    }

    if (!fs.existsSync(pluginPath)) {
      throw new Error(`Plugin file not found: ${pluginPath}`);
    }

    // Clear require cache for hot-reloading support
    delete require.cache[require.resolve(pluginPath)];
    return require(pluginPath);
  }

  // Load plugin from npm package
  _loadFromNpm(pluginDef) {
    const packageName = pluginDef.package;

    // Security: Only allow whitelisted packages
    const allowedPackages = (process.env.GATEWAY_ALLOWED_PACKAGES || '').split(',').map(p => p.trim()).filter(Boolean);

    if (allowedPackages.length > 0 && !allowedPackages.includes(packageName)) {
      throw new Error(`Package "${packageName}" is not in the allowed packages list.`);
    }

    return require(packageName);
  }

  // Load inline plugin code (from env vars or config)
  _loadInline(pluginDef) {
    const { code, name } = pluginDef;

    if (!code || typeof code !== 'string') {
      throw new Error('Inline plugin must have a "code" string property.');
    }

    // WARNING: eval() is used here intentionally for the inline plugin system.
    // In production, consider using vm.runInNewContext with restricted access.
    // This is wrapped to provide a module-like interface.
    const moduleWrapper = `
      (function(module, exports, require, __filename, __dirname) {
        ${code}
      })
    `;

    const mod = { exports: {} };
    const wrappedFn = eval(moduleWrapper);
    wrappedFn(mod, mod.exports, require, `inline-plugin-${name}`, process.cwd());

    return mod.exports;
  }

  // Load plugin in a sandboxed VM context (more secure)
  _loadSandboxed(pluginDef) {
    const { code, path: filePath, name } = pluginDef;

    let pluginCode = code;
    if (!pluginCode && filePath) {
      const resolvedPath = path.resolve(filePath);
      pluginCode = fs.readFileSync(resolvedPath, 'utf-8');
    }

    if (!pluginCode) {
      throw new Error('Sandboxed plugin must have code or a file path.');
    }

    // Create a restricted sandbox context
    const sandbox = {
      module: { exports: {} },
      exports: {},
      console: {
        log: (...args) => console.log(`[Plugin:${name}]`, ...args),
        warn: (...args) => console.warn(`[Plugin:${name}]`, ...args),
        error: (...args) => console.error(`[Plugin:${name}]`, ...args),
      },
      setTimeout,
      setInterval,
      clearTimeout,
      clearInterval,
      Buffer,
      URL,
      URLSearchParams,
      // Provide a limited require for sandboxed plugins
      require: (moduleName) => {
        const safeModules = ['url', 'querystring', 'crypto', 'util'];
        if (safeModules.includes(moduleName)) {
          return require(moduleName);
        }
        throw new Error(`Module "${moduleName}" is not allowed in sandboxed plugins.`);
      },
    };

    const context = vm.createContext(sandbox);
    const script = new vm.Script(pluginCode, {
      filename: `sandbox-plugin-${name}.js`,
      timeout: 5000,
    });

    script.runInContext(context);

    return sandbox.module.exports || sandbox.exports;
  }

  // Register plugin hooks with priority ordering
  _registerHooks(name, pluginModule, priority) {
    for (const hookName of Object.keys(this.hooks)) {
      if (typeof pluginModule[hookName] === 'function') {
        this.hooks[hookName].push({
          name,
          priority,
          handler: pluginModule[hookName].bind(pluginModule),
        });

        // Sort by priority (lower number = higher priority)
        this.hooks[hookName].sort((a, b) => a.priority - b.priority);
      }
    }
  }

  // Execute all handlers for a specific hook
  async executeHook(hookName, context) {
    const handlers = this.hooks[hookName] || [];

    for (const { name, handler } of handlers) {
      try {
        const result = await handler(context);

        // If a handler returns false, stop the chain
        if (result === false) {
          console.log(`[PluginManager] Hook chain "${hookName}" stopped by plugin "${name}".`);
          return false;
        }

        // If a handler returns a modified context, use it
        if (result && typeof result === 'object') {
          Object.assign(context, result);
        }
      } catch (error) {
        console.error(`[PluginManager] Error in plugin "${name}" hook "${hookName}":`, error.message);

        // Execute error hooks if this isn't already an error hook
        if (hookName !== 'onError') {
          await this.executeHook('onError', { ...context, error, pluginName: name });
        }
      }
    }

    return context;
  }

  // Unload a plugin by name
  unloadPlugin(name) {
    if (!this.plugins.has(name)) {
      console.warn(`[PluginManager] Plugin "${name}" not found.`);
      return false;
    }

    const plugin = this.plugins.get(name);

    // Call shutdown if available
    if (typeof plugin.module.shutdown === 'function') {
      plugin.module.shutdown();
    }

    // Remove hooks
    for (const hookName of Object.keys(this.hooks)) {
      this.hooks[hookName] = this.hooks[hookName].filter(h => h.name !== name);
    }

    this.plugins.delete(name);
    console.log(`[PluginManager] Plugin "${name}" unloaded.`);
    return true;
  }

  // Reload a plugin
  reloadPlugin(name) {
    const plugin = this.plugins.get(name);
    if (!plugin) {
      console.warn(`[PluginManager] Plugin "${name}" not found for reload.`);
      return false;
    }

    this.unloadPlugin(name);
    this.loadPlugin(plugin.definition);
    return true;
  }

  // List all loaded plugins
  listPlugins() {
    const result = [];
    for (const [name, { definition }] of this.plugins) {
      result.push({
        name,
        type: definition.type,
        enabled: definition.enabled !== false,
        priority: definition.priority || 10,
      });
    }
    return result;
  }
}

