// Route Manager - Handles routing configuration
// ============================================================
class RouteManager {
  constructor() {
    this.routes = [];
  }

  loadFromConfig(config) {
    if (config.routes && Array.isArray(config.routes)) {
      this.routes = config.routes.map(route => ({
        ...route,
        pathRegex: this._pathToRegex(route.path),
      }));
    }
  }

  _pathToRegex(pathPattern) {
    const regexStr = pathPattern
      .replace(/\*/g, '.*')
      .replace(/:(\w+)/g, '(?<$1>[^/]+)');
    return new RegExp(`^${regexStr}$`);
  }

  findRoute(method, pathname) {
    for (const route of this.routes) {
      if (route.methods && !route.methods.includes(method.toUpperCase())) {
        continue;
      }

      const match = pathname.match(route.pathRegex);
      if (match) {
        return {
          route,
          params: match.groups || {},
        };
      }
    }
    return null;
  }
}

// ============================================================
// Request Context - Shared context passed through the pipeline
// ============================================================
class RequestContext {
  constructor(req, res) {
    this.req = req;
    this.res = res;
    this.startTime = Date.now();
    this.id = this._generateId();
    this.metadata = {};
    this.requestBody = null;
    this.responseBody = null;
    this.responseHeaders = {};
    this.statusCode = 200;
    this.route = null;
    this.params = {};
    this.query = {};
    this.aborted = false;
    this.upstreamResponse = null;
  }

  _generateId() {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  get method() {
    return this.req.method;
  }

  get url() {
    return this.req.url;
  }

  get headers() {
    return this.req.headers;
  }

  get pathname() {
    return url.parse(this.req.url).pathname;
  }

  setHeader(name, value) {
    this.responseHeaders[name] = value;
  }

  setStatus(code) {
    this.statusCode = code;
  }

  setBody(body) {
    this.responseBody = body;
  }

  abort(statusCode = 403, message = 'Forbidden') {
    this.aborted = true;
    this.statusCode = statusCode;
    this.responseBody = JSON.stringify({ error: message });
  }
}

